/**
 * Shipment Request Validator
 *
 * Rules (derived from acceptance criteria AC1–AC7):
 *   AC1: All required fields present and valid → { valid: true, errors: [] }
 *   AC2: recipient_name missing or empty → REQUIRED error
 *   AC3: weight_kg is 0 or negative → MUST_BE_POSITIVE error
 *   AC4: weight_kg > 1000 → EXCEEDS_MAX error
 *   AC5: shipment_type "express" + saturday_delivery not provided → REQUIRED_FOR_EXPRESS
 *   AC6: shipment_type "standard" + saturday_delivery provided → NOT_APPLICABLE_FOR_STANDARD
 *   AC7: All errors are collected (no fail-fast) — every failing rule fires independently
 */

export type ShipmentType = "express" | "standard";

export interface ShipmentRequest {
  recipient_name?: string;
  weight_kg?: number;
  shipment_type?: ShipmentType;
  saturday_delivery?: boolean;
}

export interface ValidationError {
  field: string;
  code: string;
}

export interface ValidationResult {
  valid: boolean;
  errors: ValidationError[];
}

export function validateShipmentRequest(
  input: ShipmentRequest
): ValidationResult {
  const errors: ValidationError[] = [];

  // AC2: recipient_name must be present and non-empty
  if (
    input.recipient_name === undefined ||
    input.recipient_name === null ||
    input.recipient_name.trim() === ""
  ) {
    errors.push({ field: "recipient_name", code: "REQUIRED" });
  }

  // AC3: weight_kg must be positive (> 0)
  if (input.weight_kg !== undefined && input.weight_kg <= 0) {
    errors.push({ field: "weight_kg", code: "MUST_BE_POSITIVE" });
  }

  // AC4: weight_kg must not exceed 1000
  if (input.weight_kg !== undefined && input.weight_kg > 1000) {
    errors.push({ field: "weight_kg", code: "EXCEEDS_MAX" });
  }

  // AC5: express shipments require saturday_delivery to be explicitly provided
  if (
    input.shipment_type === "express" &&
    input.saturday_delivery === undefined
  ) {
    errors.push({ field: "saturday_delivery", code: "REQUIRED_FOR_EXPRESS" });
  }

  // AC6: standard shipments cannot specify saturday_delivery
  if (
    input.shipment_type === "standard" &&
    input.saturday_delivery !== undefined
  ) {
    errors.push({
      field: "saturday_delivery",
      code: "NOT_APPLICABLE_FOR_STANDARD",
    });
  }

  return {
    valid: errors.length === 0,
    errors,
  };
}

